import java.util.ArrayDeque;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Map;

public class HeavyLightDecomposition {
    @SuppressWarnings("unchecked")
    public static int[] hldPathQuery(int n, int[][] edges, int[] values, List<Map<Object, Object>> queries) {
        if (n <= 0) {
            return new int[0];
        }

        List<List<Integer>> adjacency = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adjacency.add(new ArrayList<>());
        }
        for (int[] edge : edges) {
            adjacency.get(edge[0]).add(edge[1]);
            adjacency.get(edge[1]).add(edge[0]);
        }

        int[] parent = new int[n];
        int[] depth = new int[n];
        Arrays.fill(parent, -1);
        ArrayDeque<Integer> queue = new ArrayDeque<>();
        queue.add(0);
        parent[0] = 0;

        while (!queue.isEmpty()) {
            int node = queue.removeFirst();
            for (int next : adjacency.get(node)) {
                if (parent[next] != -1) {
                    continue;
                }
                parent[next] = node;
                depth[next] = depth[node] + 1;
                queue.addLast(next);
            }
        }

        int[] result = new int[queries.size()];
        for (int i = 0; i < queries.size(); i++) {
            Map<Object, Object> query = queries.get(i);
            String type = String.valueOf(query.get("type"));
            int u = ((Number) query.get("u")).intValue();
            int v = ((Number) query.get("v")).intValue();
            List<Integer> pathValues = collectPathValues(u, v, parent, depth, values);
            if ("max".equals(type)) {
                int best = Integer.MIN_VALUE;
                for (int value : pathValues) {
                    best = Math.max(best, value);
                }
                result[i] = best;
            } else {
                int sum = 0;
                for (int value : pathValues) {
                    sum += value;
                }
                result[i] = sum;
            }
        }

        return result;
    }

    private static List<Integer> collectPathValues(int start, int end, int[] parent, int[] depth, int[] values) {
        int u = start;
        int v = end;
        List<Integer> up = new ArrayList<>();
        List<Integer> down = new ArrayList<>();

        while (depth[u] > depth[v]) {
            up.add(values[u]);
            u = parent[u];
        }
        while (depth[v] > depth[u]) {
            down.add(values[v]);
            v = parent[v];
        }
        while (u != v) {
            up.add(values[u]);
            down.add(values[v]);
            u = parent[u];
            v = parent[v];
        }
        up.add(values[u]);
        for (int i = down.size() - 1; i >= 0; i--) {
            up.add(down.get(i));
        }
        return up;
    }
}

fun hldPathQuery(n: Int, edges: Array<IntArray>, values: IntArray, queries: Array<String>): IntArray {
    val adjacency = Array(n) { mutableListOf<Int>() }
    for (edge in edges) {
        if (edge.size >= 2) {
            val u = edge[0]
            val v = edge[1]
            adjacency[u].add(v)
            adjacency[v].add(u)
        }
    }

    val parent = IntArray(n) { -1 }
    val depth = IntArray(n)
    val queue = ArrayDeque<Int>()
    queue.addLast(0)
    parent[0] = 0

    while (queue.isNotEmpty()) {
        val node = queue.removeFirst()
        for (next in adjacency[node]) {
            if (parent[next] != -1) {
                continue
            }
            parent[next] = node
            depth[next] = depth[node] + 1
            queue.addLast(next)
        }
    }

    fun pathNodes(start: Int, end: Int): List<Int> {
        var u = start
        var v = end
        val left = mutableListOf<Int>()
        val right = mutableListOf<Int>()

        while (depth[u] > depth[v]) {
            left.add(u)
            u = parent[u]
        }
        while (depth[v] > depth[u]) {
            right.add(v)
            v = parent[v]
        }
        while (u != v) {
            left.add(u)
            right.add(v)
            u = parent[u]
            v = parent[v]
        }
        left.add(u)
        right.reverse()
        left.addAll(right)
        return left
    }

    val results = mutableListOf<Int>()
    for (query in queries) {
        val parts = query.split(" ").filter { it.isNotEmpty() }
        if (parts.size < 3) {
            continue
        }
        val op = parts[0]
        val u = parts[1].toInt()
        val v = parts[2].toInt()
        val nodes = pathNodes(u, v)
        if (op == "max") {
            results.add(nodes.maxOf { values[it] })
        } else {
            results.add(nodes.sumOf { values[it] })
        }
    }

    return results.toIntArray()
}

func hldPathQuery(_ n: Int, _ edges: [[Int]], _ values: [Int], _ queries: [(String, Int, Int)]) -> [Int] {
    if n <= 0 { return [] }

    var adjacency = Array(repeating: [Int](), count: n)
    for edge in edges where edge.count >= 2 {
        let u = edge[0]
        let v = edge[1]
        adjacency[u].append(v)
        adjacency[v].append(u)
    }

    var parent = Array(repeating: -1, count: n)
    var depth = Array(repeating: 0, count: n)
    var queue = [0]
    var head = 0
    parent[0] = 0

    while head < queue.count {
        let node = queue[head]
        head += 1
        for next in adjacency[node] where parent[next] == -1 {
            parent[next] = node
            depth[next] = depth[node] + 1
            queue.append(next)
        }
    }

    func pathValues(_ start: Int, _ end: Int) -> [Int] {
        var u = start
        var v = end
        var up: [Int] = []
        var down: [Int] = []

        while depth[u] > depth[v] {
            up.append(values[u])
            u = parent[u]
        }
        while depth[v] > depth[u] {
            down.append(values[v])
            v = parent[v]
        }
        while u != v {
            up.append(values[u])
            down.append(values[v])
            u = parent[u]
            v = parent[v]
        }

        up.append(values[u])
        return up + down.reversed()
    }

    return queries.map { query in
        let vals = pathValues(query.1, query.2)
        if query.0 == "max" {
            return vals.max() ?? 0
        }
        return vals.reduce(0, +)
    }
}
